#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_V 100

typedef struct {
    int V;
    int* graph[MAX_V];
    int sizes[MAX_V];
} Graph;

void initGraph(Graph* g, int vertices) {
    g->V = vertices;
    for (int i = 0; i < vertices; i++) {
        g->graph[i] = (int*)malloc(MAX_V * sizeof(int));
        g->sizes[i] = 0;
    }
}

void addEdge(Graph* g, int u, int v) {
    g->graph[u][g->sizes[u]++] = v;
    g->graph[v][g->sizes[v]++] = u;
}

void dfs(Graph* g, int v, bool* visited) {
    visited[v] = true;
    for (int i = 0; i < g->sizes[v]; i++) {
        int u = g->graph[v][i];
        if (!visited[u]) dfs(g, u, visited);
    }
}

bool isConnected(Graph* g) {
    bool* visited = (bool*)calloc(g->V, sizeof(bool));
    dfs(g, 0, visited);
    for (int i = 0; i < g->V; i++) {
        if (!visited[i]) {
            free(visited);
            return false;
        }
    }
    free(visited);
    return true;
}

bool isEulerian(Graph* g) {
    if (!isConnected(g)) return false;
    int odd = 0;
    for (int i = 0; i < g->V; i++) {
        if (g->sizes[i] % 2 != 0) odd++;
    }
    return odd == 0 || odd == 2;
}

int* findEulerianPath(Graph* g, int* resultSize) {
    if (!isEulerian(g)) {
        *resultSize = 0;
        return NULL;
    }
    int* result = (int*)malloc(g->V * 2 * sizeof(int));
    int* stack = (int*)malloc(g->V * 2 * sizeof(int));
    int top = 0, resIdx = 0;
    stack[top++] = 0;
    int** tempGraph = (int**)malloc(g->V * sizeof(int*));
    int* tempSizes = (int*)malloc(g->V * sizeof(int));
    for (int i = 0; i < g->V; i++) {
        tempGraph[i] = (int*)malloc(g->sizes[i] * sizeof(int));
        for (int j = 0; j < g->sizes[i]; j++) tempGraph[i][j] = g->graph[i][j];
        tempSizes[i] = g->sizes[i];
    }
    while (top > 0) {
        int u = stack[top - 1];
        if (tempSizes[u] > 0) {
            int v = tempGraph[u][0];
            tempGraph[u][0] = tempGraph[u][--tempSizes[u]];
            for (int i = 0; i < tempSizes[v]; i++) {
                if (tempGraph[v][i] == u) {
                    tempGraph[v][i] = tempGraph[v][--tempSizes[v]];
                    break;
                }
            }
            stack[top++] = v;
        } else {
            result[resIdx++] = stack[--top];
        }
    }
    *resultSize = resIdx;
    for (int i = 0; i < g->V; i++) free(tempGraph[i]);
    free(tempGraph);
    free(tempSizes);
    free(stack);
    return result;
}

int main() {
    Graph g;
    initGraph(&g, 4);
    addEdge(&g, 0, 1);
    addEdge(&g, 1, 2);
    addEdge(&g, 2, 3);
    addEdge(&g, 3, 0);
    int resultSize;
    int* path = findEulerianPath(&g, &resultSize);
    if (path) {
        printf("Eulerian Path: [");
        for (int i = resultSize - 1; i >= 0; i--) {
            printf("%d", path[i]);
            if (i > 0) printf(", ");
        }
        printf("]\n");
        free(path);
    } else {
        printf("Eulerian yol yoxdur\n");
    }
    for (int i = 0; i < g.V; i++) free(g.graph[i]);
    return 0;
}
