using System;
using System.Collections.Generic;
using System.Linq;

class Graph {
    private int V;
    private List<int>[] graph;

    public Graph(int vertices) {
        V = vertices;
        graph = new List<int>[vertices];
        for (int i = 0; i < vertices; i++) graph[i] = new List<int>();
    }

    public void AddEdge(int u, int v) {
        graph[u].Add(v);
        graph[v].Add(u);
    }

    private void Dfs(int v, bool[] visited) {
        visited[v] = true;
        foreach (int u in graph[v]) {
            if (!visited[u]) Dfs(u, visited);
        }
    }

    public bool IsConnected() {
        bool[] visited = new bool[V];
        Dfs(0, visited);
        return visited.All(x => x);
    }

    public bool IsEulerian() {
        if (!IsConnected()) return false;
        int odd = graph.Count(g => g.Count % 2 != 0);
        return odd == 0 || odd == 2;
    }

    public List<int> FindEulerianPath() {
        if (!IsEulerian()) return new List<int> { -1 }; // 'Eulerian yol yoxdur' əvəzinə
        var result = new List<int>();
        var stack = new Stack<int>();
        stack.Push(0);
        var tempGraph = graph.Select(g => g.ToList()).ToArray();
        while (stack.Count > 0) {
            int u = stack.Peek();
            if (tempGraph[u].Count > 0) {
                int v = tempGraph[u][0];
                tempGraph[u].Remove(v);
                tempGraph[v].Remove(u);
                stack.Push(v);
            } else {
                result.Add(stack.Pop());
            }
        }
        result.Reverse();
        return result;
    }
}

class Program {
    static void Main() {
        var g = new Graph(4);
        g.AddEdge(0, 1);
        g.AddEdge(1, 2);
        g.AddEdge(2, 3);
        g.AddEdge(3, 0);
        Console.WriteLine("Eulerian Path: [" + string.Join(", ", g.FindEulerianPath()) + "]");
    }
}
