#include <stack>
#include <algorithm>

class Graph {
    int V;
    std::vector<std::vector<int>> graph;

public:
    Graph(int vertices) : V(vertices), graph(vertices) {}

    void addEdge(int u, int v) {
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    void dfs(int v, std::vector<bool>& visited) {
        visited[v] = true;
        for (int u : graph[v]) {
            if (!visited[u]) dfs(u, visited);
        }
    }

    bool isConnected() {
        std::vector<bool> visited(V, false);
        dfs(0, visited);
        return std::all_of(visited.begin(), visited.end(), [](bool v) { return v; });
    }

    bool isEulerian() {
        if (!isConnected()) return false;
        int odd = 0;
        for (int i = 0; i < V; i++) {
            if (graph[i].size() % 2 != 0) odd++;
        }
        return odd == 0 || odd == 2;
    }

    std::vector<int> findEulerianPath() {
        if (!isEulerian()) return {-1}; // 'Eulerian yol yoxdur' əvəzinə
        std::vector<int> result;
        std::stack<int> stack;
        stack.push(0);
        std::vector<std::vector<int>> tempGraph = graph;
        while (!stack.empty()) {
            int u = stack.top();
            if (!tempGraph[u].empty()) {
                int v = tempGraph[u].back();
                tempGraph[u].pop_back();
                tempGraph[v].erase(std::remove(tempGraph[v].begin(), tempGraph[v].end(), u), tempGraph[v].end());
                stack.push(v);
            } else {
                result.push_back(stack.top());
                stack.pop();
            }
        }
        std::reverse(result.begin(), result.end());
        return result;
    }
};

int main() {
    Graph g(4);
    g.addEdge(0, 1);
    g.addEdge(1, 2);
    g.addEdge(2, 3);
    g.addEdge(3, 0);
    auto path = g.findEulerianPath();
    std::cout << "Eulerian Path: [";
    for (size_t i = 0; i < path.size(); i++) {
        std::cout << path[i];
        if (i < path.size() - 1) std::cout << ", ";
    }
    std::cout << "]" << std::endl;
    return 0;
}
